/**
 * @name Taint flow from HTTP request to file system operations
 * @description User-controlled input from HTTP request reaching file system operations without validation
 * @kind path-problem
 * @problem.severity error
 * @id java/http-to-file-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PathTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // File constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "File") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // FileInputStream / FileOutputStream
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileInputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.io", "FileOutputStream") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Paths.get
    exists(MethodCall mc |
      mc.getMethod().hasName("get") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.nio.file", "Paths") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Path.resolve
    exists(MethodCall mc |
      mc.getMethod().hasName("resolve") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.nio.file", "Path") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module PathTraversalFlow = TaintTracking::Global<PathTraversalConfig>;
import PathTraversalFlow::PathGraph

from PathTraversalFlow::PathNode source, PathTraversalFlow::PathNode sink
where PathTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential path traversal: HTTP input flows to file system operation from $@.", source.getNode(), "user input"

/**
 * @name ClassLoader resource loading with user-controlled path
 * @description User-controlled input flowing to ClassLoader.getResource or getResourceAsStream
 * @kind path-problem
 * @problem.severity error
 * @id java/classloader-path-traversal
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ClassLoaderPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Class.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Spring ClassPathResource
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "ClassPathResource") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // Spring FileSystemResource
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("org.springframework.core.io", "FileSystemResource") and
      sink.asExpr() = ce.getArgument(0)
    )
    or
    // ResourceUtils.getFile or getURL
    exists(MethodCall mc |
      (mc.getMethod().hasName("getFile") or mc.getMethod().hasName("getURL")) and
      mc.getMethod().getDeclaringType().hasQualifiedName("org.springframework.util", "ResourceUtils") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ClassLoaderPathFlow = TaintTracking::Global<ClassLoaderPathConfig>;
import ClassLoaderPathFlow::PathGraph

from ClassLoaderPathFlow::PathNode source, ClassLoaderPathFlow::PathNode sink
where ClassLoaderPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled path reaches ClassLoader/ClassPath resource loading from $@.", source.getNode(), "user input"

/**
 * @name OpenApiInterceptor path traversal via getPathInfo to getResource
 * @description getPathInfo from HTTP request flowing to ClassLoader.getResource in OpenApiInterceptor
 * @kind path-problem
 * @problem.severity error
 * @id java/openapi-pathinfo-to-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module OpenApiPathConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getPathInfo, getRequestURI, getServletPath from HttpServletRequest
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("getPathInfo") or
        mc.getMethod().hasName("getRequestURI") or
        mc.getMethod().hasName("getServletPath") or
        mc.getMethod().hasName("getRequestURL")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream
    exists(MethodCall mc |
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "ClassLoader") or
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Class")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Spring ClassPathUtil or similar
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      mc.getMethod().getDeclaringType().hasQualifiedName("ca.uhn.fhir.util", "ClasspathUtil") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module OpenApiPathFlow = TaintTracking::Global<OpenApiPathConfig>;
import OpenApiPathFlow::PathGraph

from OpenApiPathFlow::PathNode source, OpenApiPathFlow::PathNode sink
where OpenApiPathFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP path info flows to ClassLoader.getResource in OpenApiInterceptor from $@.", source.getNode(), "HTTP request path"

/**
 * @name OpenApiInterceptor full path traversal analysis
 * @description Trace getPathInfo through substring to getResource call
 * @kind path-problem
 * @problem.severity error
 * @id java/openapi-pathinfo-substring-to-getresource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module OpenApiDetailedConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Any method call that reads from HttpServletRequest in OpenApiInterceptor
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      (
        mc.getMethod().hasName("getPathInfo") or
        mc.getMethod().hasName("getRequestURI") or
        mc.getMethod().hasName("getServletPath")
      ) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream in OpenApiInterceptor
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClasspathUtil.loadResource
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      (mc.getMethod().hasName("loadResource") or mc.getMethod().hasName("loadCompressedResource")) and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module OpenApiDetailedFlow = TaintTracking::Global<OpenApiDetailedConfig>;
import OpenApiDetailedFlow::PathGraph

from OpenApiDetailedFlow::PathNode source, OpenApiDetailedFlow::PathNode sink
where OpenApiDetailedFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP path flows to resource loading in OpenApiInterceptor from $@.", source.getNode(), "HTTP path"

/**
 * @name OpenApiInterceptor - parameter to handleResourceRequest to getResource
 * @description Trace the path parameter through serveSwaggerUi -> handleResourceRequest -> getResource
 * @kind path-problem
 * @problem.severity error
 * @id java/openapi-param-to-resource
 * @tags security
 *       external/cwe/cwe-022
 *       external/cwe/cwe-706
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.DataFlow

module OpenApiResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Parameters of handleResourceRequest (which receives the path from serveSwaggerUi)
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      p.getCallable().hasName("handleResourceRequest") and
      source.asParameter() = p
    )
    or
    // Parameters of serveSwaggerUi
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      p.getCallable().hasName("serveSwaggerUi") and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // ClassLoader.getResource / getResourceAsStream 
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      (mc.getMethod().hasName("getResource") or mc.getMethod().hasName("getResourceAsStream")) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ClasspathUtil calls
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("ca.uhn.fhir.rest.openapi", "OpenApiInterceptor") and
      mc.getMethod().getDeclaringType().hasQualifiedName("ca.uhn.fhir.util", "ClasspathUtil") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module OpenApiResourceFlow = TaintTracking::Global<OpenApiResourceConfig>;
import OpenApiResourceFlow::PathGraph

from OpenApiResourceFlow::PathNode source, OpenApiResourceFlow::PathNode sink
where OpenApiResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "HTTP path parameter flows to resource loading in OpenApiInterceptor from $@.", source.getNode(), "parameter"
